import{_ as t,o as a,c as o,S as i}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Text to Speech","description":"","frontmatter":{},"headers":[],"relativePath":"Text-to-Speech.md","filePath":"Text-to-Speech.md","lastUpdated":null}'),n={name:"Text-to-Speech.md"};function s(r,e,l,d,c,g){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="text-to-speech" tabindex="-1">Text to Speech <a class="header-anchor" href="#text-to-speech" aria-label="Permalink to &quot;Text to Speech&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Text to Speech (TTS) can read card content aloud.</p><p>This helps with language study, listening practice, and accessibility.</p><p>Sprout also supports flag-aware voice routing with <a href="./Flags">inline flag tokens</a>. Flag assets are provided by <a href="https://github.com/HatScripts/circle-flags" target="_blank" rel="noreferrer">HatScripts/circle-flags</a> (MIT).</p><h2 id="supported-card-types" tabindex="-1">Supported card types <a class="header-anchor" href="#supported-card-types" aria-label="Permalink to &quot;Supported card types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card type</th><th>TTS support</th><th>What&#39;s read</th></tr></thead><tbody><tr><td><strong>Basic</strong></td><td>✅</td><td>Question and/or answer fields</td></tr><tr><td><strong>Cloze</strong></td><td>✅</td><td>Full sentence or just the cloze deletion (configurable)</td></tr><tr><td><strong>MCQ</strong></td><td>✅</td><td>Question stem and options</td></tr><tr><td><strong>Ordered</strong></td><td>✅</td><td>Question stem and items</td></tr><tr><td><strong>Image Occlusion</strong></td><td>❌</td><td>Not supported (visual cards)</td></tr></tbody></table><p>If a card type is unsupported, no TTS audio is generated for that card.</p><h2 id="cloze-tts-options" tabindex="-1">Cloze TTS options <a class="header-anchor" href="#cloze-tts-options" aria-label="Permalink to &quot;Cloze TTS options&quot;">​</a></h2><p>For cloze cards, choose what is read on the answer side:</p><table tabindex="0"><thead><tr><th>Option</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Deletion only</strong></td><td>Reads only the hidden/deleted text (e.g. &quot;Paris&quot;)</td></tr><tr><td><strong>Full sentence</strong></td><td>Reads the complete sentence with the deletion filled in (e.g. &quot;The capital of France is Paris&quot;)</td></tr></tbody></table><p>Configure this in <strong>Settings → Audio → Cloze TTS mode</strong>.</p><h2 id="enabling-tts" tabindex="-1">Enabling TTS <a class="header-anchor" href="#enabling-tts" aria-label="Permalink to &quot;Enabling TTS&quot;">​</a></h2><ol><li>Go to <strong>Settings → Audio</strong>.</li><li>Toggle <strong>Enable text-to-speech</strong> on.</li><li>Choose voice and language (see <a href="./Language-Settings">Language Settings</a>).</li><li>TTS controls will appear in the study session interface.</li></ol><h2 id="flag-aware-voice-routing" tabindex="-1">Flag-aware voice routing <a class="header-anchor" href="#flag-aware-voice-routing" aria-label="Permalink to &quot;Flag-aware voice routing&quot;">​</a></h2><p>In <strong>Settings → Audio → Flag-aware routing</strong>:</p><ul><li><strong>Use flags for language and accent</strong> (default: on) <ul><li><code>{{es}}</code> and <code>{{es-mx}}</code> can switch spoken language/accent.</li><li>A single flag anywhere in the text can apply to the full spoken content.</li><li>Multiple flags in one field use segmented speaking (voice switches inline).</li></ul></li><li><strong>Speak language name before flag segments</strong> (default: off) <ul><li>Adds a spoken language prefix before each flag-switched segment.</li><li>English variants use the label <strong>English</strong> while keeping regional accent (for example UK/US voice choice).</li></ul></li></ul><p>See <a href="./Flags">Flags</a> for token syntax and supported formats, and <a href="./Flag-Codes">Flag Codes</a> for available language/region codes.</p><h2 id="during-a-session" tabindex="-1">During a session <a class="header-anchor" href="#during-a-session" aria-label="Permalink to &quot;During a session&quot;">​</a></h2><p>When TTS is enabled:</p><ul><li>A <strong>speaker icon</strong> appears on cards during review.</li><li>Click it to hear the current side read aloud.</li><li>Auto-play can be configured to read automatically when a card is shown or when the answer is revealed.</li></ul><h2 id="audio-quality" tabindex="-1">Audio quality <a class="header-anchor" href="#audio-quality" aria-label="Permalink to &quot;Audio quality&quot;">​</a></h2><p>TTS uses your device&#39;s built-in speech engine. Voice quality and available voices depend on your OS:</p><ul><li><strong>macOS</strong> — High-quality voices available via System Preferences → Accessibility → Spoken Content.</li><li><strong>Windows</strong> — Voices available via Settings → Time &amp; Language → Speech.</li><li><strong>Linux</strong> — Depends on the installed speech synthesis packages.</li><li><strong>Mobile</strong> — Uses the device&#39;s built-in TTS engine.</li></ul><p>If no suitable voice is installed for your chosen language, pronunciation quality may be poor.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>For language learning, set the voice language to match your target language.</li><li>Use <strong>deletion only</strong> mode for cloze cards when you want to practise pronunciation of specific terms.</li><li>Use <strong>full sentence</strong> mode when context and sentence flow matter.</li><li>Use inline flags when a single card mixes languages or accents.</li></ul>',28)])])}const p=t(n,[["render",s]]);export{u as __pageData,p as default};
